import { create } from 'zustand';

interface User {
  name: string;
  email: string;
}

interface UserState {
  user: User;
  setUser: (user: User) => void;
}

export const useUserStore = create<UserState>((set) => ({
  user: { name: 'Alice', email: 'alice@example.com' },
  setUser: (user) => set({ user }),
}));
